mapper.update:
UPDATE comment
content = #{content}, like_count = #{likeCount}, reply_count = #{replyCount}, updated_at = NOW()
WHERE comment_id = #{commentId}

mapper.delete:
DELETE FROM comment
WHERE comment_id = #{commentId}
   OR parent_id = #{commentId}

mapper.select:
SELECT

FROM comment


        note_id = #{params.noteId}


ORDER BY created_at ASC, comment_id ASC
LIMIT #{pageSize} OFFSET #{offset}
